+#!/usr/bin/env node
+/**
+ * MCP Server for Episodic Memory.
+ *
+ * This server provides tools to search and explore indexed Claude Code conversations
+ * using semantic search, text search, and conversation display capabilities.
+ */
+import { Server } from '@modelcontextprotocol/sdk/server/index.js';
+import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
+import { CallToolRequestSchema, ListToolsRequestSchema, } from '@modelcontextprotocol/sdk/types.js';
+import { z } from 'zod';
+import { searchConversations, searchMultipleConcepts, formatResults, formatMultiConceptResults, } from './search.js';
+import { formatConversationAsMarkdown } from './show.js';
+import fs from 'fs';
+// Zod Schemas for Input Validation
+const SearchModeEnum = z.enum(['vector', 'text', 'both']);
+const ResponseFormatEnum = z.enum(['markdown', 'json']);
+const SearchInputSchema = z
+    .object({
+    query: z
+        .union([
+        z.string().min(2, 'Query must be at least 2 characters'),
+        z
+            .array(z.string().min(2))
+            .min(2, 'Must provide at least 2 concepts for multi-concept search')
+            .max(5, 'Cannot search more than 5 concepts at once'),
+    ])
+        .describe('Search query - string for single concept, array of strings for multi-concept AND search'),
+    mode: SearchModeEnum.default('both').describe('Search mode: "vector" for semantic similarity, "text" for exact matching, "both" for combined (default: "both"). Only used for single-concept searches.'),
+    limit: z
+        .number()
+        .int()
+        .min(1)
+        .max(50)
+        .default(10)
+        .describe('Maximum number of results to return (default: 10)'),
+    after: z
+        .string()
+        .regex(/^\d{4}-\d{2}-\d{2}$/, 'Date must be in YYYY-MM-DD format')
+        .optional()
+        .describe('Only return conversations after this date (YYYY-MM-DD format)'),
+    before: z
+        .string()
+        .regex(/^\d{4}-\d{2}-\d{2}$/, 'Date must be in YYYY-MM-DD format')
+        .optional()
+        .describe('Only return conversations before this date (YYYY-MM-DD format)'),
+    response_format: ResponseFormatEnum.default('markdown').describe('Output format: "markdown" for human-readable or "json" for machine-readable (default: "markdown")'),
+})
+    .strict();
+const ShowConversationInputSchema = z
+    .object({
+    path: z
+        .string()
+        .min(1, 'Path is required')
+        .describe('Absolute path to the JSONL conversation file to display'),
+    startLine: z
+        .number()
+        .int()
+        .min(1)
+        .optional()
+        .describe('Starting line number (1-indexed, inclusive). Omit to start from beginning.'),
+    endLine: z
+        .number()
+        .int()
+        .min(1)
+        .optional()
+        .describe('Ending line number (1-indexed, inclusive). Omit to read to end.'),
+})
+    .strict();
+// Error Handling Utility
+function handleError(error) {
+    if (error instanceof Error) {
+        return `Error: ${error.message}`;
+    }
+    return `Error: ${String(error)}`;
+}
+// Create MCP Server
+const server = new Server({
+    name: 'episodic-memory',
+    version: '1.0.0',
+}, {
+    capabilities: {
+        tools: {},
+    },
+});
+// Register Tools
+server.setRequestHandler(ListToolsRequestSchema, async () => {
+    return {
+        tools: [
+            {
+                name: 'search',
+                description: `Find past decisions, solutions, and context from previous conversations. Search before implementing features, debugging issues, or making technical decisions - past context prevents reinventing solutions and repeating mistakes. Use single string for semantic search or array of 2-5 concepts for precise AND matching. Returns ranked results with project, date, snippets, and file paths.`,
+                inputSchema: {
+                    type: 'object',
+                    properties: {
+                        query: {
+                            oneOf: [
+                                { type: 'string', minLength: 2 },
+                                { type: 'array', items: { type: 'string', minLength: 2 }, minItems: 2, maxItems: 5 },
+                            ],
+                        },
+                        mode: { type: 'string', enum: ['vector', 'text', 'both'], default: 'both' },
+                        limit: { type: 'number', minimum: 1, maximum: 50, default: 10 },
+                        after: { type: 'string', pattern: '^\\d{4}-\\d{2}-\\d{2}$' },
+                        before: { type: 'string', pattern: '^\\d{4}-\\d{2}-\\d{2}$' },
+                        response_format: { type: 'string', enum: ['markdown', 'json'], default: 'markdown' },
+                    },
+                    required: ['query'],
+                    additionalProperties: false,
+                },
+                annotations: {
+                    title: 'Search Episodic Memory',
+                    readOnlyHint: true,
+                    destructiveHint: false,
+                    idempotentHint: true,
+                    openWorldHint: false,
+                },
+            },
+            {
+                name: 'read',
+                description: `Read full conversations to extract detailed context after finding relevant results with search. Essential for understanding the complete rationale, evolution, and gotchas behind past decisions. Use startLine/endLine pagination for large conversations to avoid context bloat (line numbers are 1-indexed).`,
+                inputSchema: {
+                    type: 'object',
+                    properties: {
+                        path: { type: 'string', minLength: 1 },
+                        startLine: { type: 'number', minimum: 1 },
+                        endLine: { type: 'number', minimum: 1 },
+                    },
+                    required: ['path'],
+                    additionalProperties: false,
+                },
+                annotations: {
+                    title: 'Show Full Conversation',
+                    readOnlyHint: true,
+                    destructiveHint: false,
+                    idempotentHint: true,
+                    openWorldHint: false,
+                },
+            },
+        ],
+    };
+});
+// Handle Tool Calls
+server.setRequestHandler(CallToolRequestSchema, async (request) => {
+    try {
+        const { name, arguments: args } = request.params;
+        if (name === 'search') {
+            const params = SearchInputSchema.parse(args);
+            let resultText;
+            // Check if query is array (multi-concept) or string (single-concept)
+            if (Array.isArray(params.query)) {
+                // Multi-concept search
+                const options = {
+                    limit: params.limit,
+                    after: params.after,
+                    before: params.before,
+                };
+                const results = await searchMultipleConcepts(params.query, options);
+                if (params.response_format === 'json') {
+                    resultText = JSON.stringify({
+                        results: results,
+                        count: results.length,
+                        concepts: params.query,
+                    }, null, 2);
+                }
+                else {
+                    resultText = formatMultiConceptResults(results, params.query);
+                }
+            }
+            else {
+                // Single-concept search
+                const options = {
+                    mode: params.mode,
+                    limit: params.limit,
+                    after: params.after,
+                    before: params.before,
+                };
+                const results = await searchConversations(params.query, options);
+                if (params.response_format === 'json') {
+                    resultText = JSON.stringify({
+                        results: results.map((r) => ({
+                            exchange: r.exchange,
+                            similarity: r.similarity,
+                            snippet: r.snippet,
+                        })),
+                        count: results.length,
+                        mode: params.mode,
+                    }, null, 2);
+                }
+                else {
+                    resultText = formatResults(results);
+                }
+            }
+            return {
+                content: [
+                    {
+                        type: 'text',
+                        text: resultText,
+                    },
+                ],
+            };
+        }
+        if (name === 'read') {
+            const params = ShowConversationInputSchema.parse(args);
+            // Verify file exists
+            if (!fs.existsSync(params.path)) {
+                throw new Error(`File not found: ${params.path}`);
+            }
+            // Read and format conversation with optional line range
+            const jsonlContent = fs.readFileSync(params.path, 'utf-8');
+            const markdownContent = formatConversationAsMarkdown(jsonlContent, params.startLine, params.endLine);
+            return {
+                content: [
+                    {
+                        type: 'text',
+                        text: markdownContent,
+                    },
+                ],
+            };
+        }
+        throw new Error(`Unknown tool: ${name}`);
+    }
+    catch (error) {
+        // Return errors within the result (not as protocol errors)
+        return {
+            content: [
+                {
+                    type: 'text',
+                    text: handleError(error),
+                },
+            ],
+            isError: true,
+        };
+    }
+});
+// Main Function
+async function main() {
+    console.error('Episodic Memory MCP server running via stdio');
+    const transport = new StdioServerTransport();
+    await server.connect(transport);
+}
+// Run the Server
+main().catch((error) => {
+    console.error('Server error:', error);
+    process.exit(1);
+});

